import{_ as a,o as e,c as n,R as s}from"./chunks/framework.e3a68582.js";const g=JSON.parse('{"title":"约定式提交","description":"","frontmatter":{},"headers":[],"relativePath":"blogs/2023/03/conventional-commits.md","filePath":"blogs/2023/03/conventional-commits.md","lastUpdated":1683265338000}'),l={name:"blogs/2023/03/conventional-commits.md"},t=s(`<h1 id="约定式提交" tabindex="-1">约定式提交 <a class="header-anchor" href="#约定式提交" aria-label="Permalink to &quot;约定式提交&quot;">​</a></h1><ul><li><a href="./semver.html">语义化版本</a></li><li>约定式提交 - 本篇</li><li><a href="./changelog.html">改动日志</a></li></ul><p>和语义化版本类似，<a href="https://www.conventionalcommits.org/zh-hans/" target="_blank" rel="noreferrer">约定式提交</a> 对我也有着特别的意义。</p><h2 id="什么是约定式提交" tabindex="-1">什么是约定式提交 <a class="header-anchor" href="#什么是约定式提交" aria-label="Permalink to &quot;什么是约定式提交&quot;">​</a></h2><p>约定式提交是一种提交信息相关的规范。</p><h2 id="基本格式" tabindex="-1">基本格式 <a class="header-anchor" href="#基本格式" aria-label="Permalink to &quot;基本格式&quot;">​</a></h2><p>最基本的约定式提交格式如下：</p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#e1e4e8;">&lt;type&gt;[optional scope]: &lt;description&gt;</span></span>
<span class="line"><span style="color:#e1e4e8;"></span></span>
<span class="line"><span style="color:#e1e4e8;">[optional body]</span></span>
<span class="line"><span style="color:#e1e4e8;"></span></span>
<span class="line"><span style="color:#e1e4e8;">[optional footer(s)]</span></span>
<span class="line"><span style="color:#e1e4e8;"></span></span>
<span class="line"><span style="color:#e1e4e8;">&lt;类型&gt;[可选 范围]: &lt;描述&gt;</span></span>
<span class="line"><span style="color:#e1e4e8;"></span></span>
<span class="line"><span style="color:#e1e4e8;">[可选 正文]</span></span>
<span class="line"><span style="color:#e1e4e8;"></span></span>
<span class="line"><span style="color:#e1e4e8;">[可选 脚注]</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292e;">&lt;type&gt;[optional scope]: &lt;description&gt;</span></span>
<span class="line"><span style="color:#24292e;"></span></span>
<span class="line"><span style="color:#24292e;">[optional body]</span></span>
<span class="line"><span style="color:#24292e;"></span></span>
<span class="line"><span style="color:#24292e;">[optional footer(s)]</span></span>
<span class="line"><span style="color:#24292e;"></span></span>
<span class="line"><span style="color:#24292e;">&lt;类型&gt;[可选 范围]: &lt;描述&gt;</span></span>
<span class="line"><span style="color:#24292e;"></span></span>
<span class="line"><span style="color:#24292e;">[可选 正文]</span></span>
<span class="line"><span style="color:#24292e;"></span></span>
<span class="line"><span style="color:#24292e;">[可选 脚注]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><ul><li>类型常常使用 <code>fix</code>（表示修复问题，对应语义化版本的 PATCH）、<code>feat</code>（表示新增功能，对应语义化版本的 MINOR），当然也有别的类型，比如 <code>build</code>（表示构建相关）、<code>docs</code>（表示文档相关）等。你可以参考 <a href="https://github.com/angular/angular.js/blob/master/DEVELOPERS.md#commits" target="_blank" rel="noreferrer">angular/angularjs DEVELOPERS.md Git Commit Guidelines</a> 和 <a href="https://github.com/angular/angular/blob/main/CONTRIBUTING.md#commit" target="_blank" rel="noreferrer">angular/angular CONTRIBUTING.md Commit Message Format</a> 了解更多类型。</li><li>在脚注中包含 <code>BREAKING CHANGE</code>: 或 <code>&lt;类型&gt;(范围)</code> 后面有一个 <code>!</code> 的提交，表示引入了破坏性 API 变更（对应语义化版本中的 MAJOR）。破坏性变更可以是任意类型提交的一部分。</li></ul><h2 id="为什么要用约定式提交" tabindex="-1">为什么要用约定式提交 <a class="header-anchor" href="#为什么要用约定式提交" aria-label="Permalink to &quot;为什么要用约定式提交&quot;">​</a></h2><p>理由和语义化版本是类似的。</p><p>约定式提交已经被广泛采用。遵循约定式提交，可以获取到清晰的提交历史，有利于编写自动化工具，自动确定语义化版本和改动日志等，可以为开发带来实打实的便利。</p><h2 id="谁在用约定式提交" tabindex="-1">谁在用约定式提交 <a class="header-anchor" href="#谁在用约定式提交" aria-label="Permalink to &quot;谁在用约定式提交&quot;">​</a></h2><p><code>npm</code>、<code>webpack</code>、<code>vite</code>、<code>rollup</code>、<code>antd</code> 等库就是遵循约定式提交的巨头。</p><h2 id="约定式提交的缺陷" tabindex="-1">约定式提交的缺陷 <a class="header-anchor" href="#约定式提交的缺陷" aria-label="Permalink to &quot;约定式提交的缺陷&quot;">​</a></h2><p>我个人认为，约定式提交有两个缺陷。</p><p>第一个缺陷是，类型对新手来说很难确定，可能会出现不够 <strong>整洁</strong> 的提交。</p><p>第二个缺陷是，描述带有主观认识，可能不够 <strong>准确</strong>。</p><h2 id="和语义化版本的关联" tabindex="-1">和语义化版本的关联 <a class="header-anchor" href="#和语义化版本的关联" aria-label="Permalink to &quot;和语义化版本的关联&quot;">​</a></h2><p>一旦你在使用约定式提交，你不再需要自行翻看提交历史来确认你的下一个版本。很多语义化版本工具可以自动确定下一个版本，一般也允许你手动确定下一个版本。但既然你已经选择了语义化版本和约定式提交，为什么不投入自动化的怀抱，让自己的生活更轻松一些呢？</p><h2 id="实践" tabindex="-1">实践 <a class="header-anchor" href="#实践" aria-label="Permalink to &quot;实践&quot;">​</a></h2><p><a href="https://github.com/conventional-changelog/commitlint" target="_blank" rel="noreferrer">commitlint</a> 是我首先推荐的工具，它能有效地检查提交信息。</p><p>我建议使用 <a href="https://www.npmjs.com/package/@commitlint/config-conventional" target="_blank" rel="noreferrer">@commitlint/config-conventional</a> 获取和约定式提交一致的体验，如果你倾向于 angular 风格，可以使用 <a href="https://www.npmjs.com/package/@commitlint/config-angular" target="_blank" rel="noreferrer">@commitlint/config-angular</a>。</p><p>而要在命令行中使用，则需要 <a href="https://www.npmjs.com/package/@commitlint/cli" target="_blank" rel="noreferrer">@commitlint/cli</a>。你可以配合 <a href="https://github.com/typicode/husky" target="_blank" rel="noreferrer">husky</a> 或者 <a href="https://github.com/toplenboren/simple-git-hooks" target="_blank" rel="noreferrer">simple-git-hooks</a> 来调用它，我更喜欢轻量的后者。</p><p>对于新手，你可以尝试使用 <a href="https://www.npmjs.com/package/commitizen" target="_blank" rel="noreferrer">commitizen</a>。它带有一些额外的提示，方便新手使用。你可以搭配 <a href="https://www.npmjs.com/package/@commitlint/cz-commitlint" target="_blank" rel="noreferrer">@commitlint/cz-commitlint</a> 或 <a href="https://www.npmjs.com/package/@commitlint/prompt" target="_blank" rel="noreferrer">@commitlint/prompt</a> 来使用。</p><p>本篇是系列的第二篇，我建议你阅读完 <a href="./semver.html">语义化版本</a>、约定式提交（就是本篇）和 <a href="./changelog.html">改动日志</a> 再开始实践！😄</p>`,26),o=[t];function r(p,c,i,m,h,d){return e(),n("div",null,o)}const u=a(l,[["render",r]]);export{g as __pageData,u as default};
